    27	func NewFileWatcher(paths []string, handler EventHandler) (*FileWatcher, error) {
    28		fw, err := fsnotify.NewWatcher()
    29		if err != nil {
    30			return nil, fmt.Errorf("create fsnotify watcher: %w", err)
    31		}
    32		return &FileWatcher{
    33			fw:      fw,
    34			paths:   paths,
    35			handler: handler,
    36			done:    make(chan struct{}),
    37			eventCh: make(chan fsnotify.Event, 256),
    38		}, nil
    39	}
    40	
    41	func (w *FileWatcher) Start() error {
    42		w.mu.Lock()
    43		defer w.mu.Unlock()
    44		if w.running {
    45			return fmt.Errorf("watcher already running")
    46		}
    47		go w.processEvents()
    48		for _, p := range w.paths {
    49			if err := w.fw.Add(p); err != nil {
    50				return fmt.Errorf("add watch path %s: %w", p, err)
    51			}
    52		}
    53		w.running = true
    54		return nil
    55	}
    56	
    57	func (w *FileWatcher) Stop() error {
    58		w.mu.Lock()
    59		defer w.mu.Unlock()
    60		if !w.running {
    61			return fmt.Errorf("watcher not running")
    62		}
    63		close(w.done)
    64		w.running = false
    65		return w.fw.Close()
    66	}
    67	
    68	func (w *FileWatcher) processEvents() {
    69		for {
    70		select {
    71		case ev, ok := <-w.fw.Events:
    72			if !ok {
    73				return
    74			}
    75			go w.handleEvent(ev)
    76		case err, ok := <-w.fw.Errors:
    77			if !ok {
    78				return
    79			}
    80			fmt.Fprintf(os.Stderr, "watcher error: %v\n", err)
    81		case <-w.done:
    82			return
    83		}
    84	}
    85	}
    86	
    87	func (w *FileWatcher) handleEvent(ev fsnotify.Event) {
    88		if ev.Op&fsnotify.Create == fsnotify.Create {
    89			if info, err := os.Stat(ev.Name); err == nil && info.IsDir() {
    90				_ = w.fw.Add(ev.Name)
    91			}
    92		}
    93		w.handler.Handle(ev)
    94	}
