use bitvec::prelude::*;
use serde::{Deserialize, Serialize};
use std::hash::{Hash, Hasher};

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BloomFilter {
    #[serde(serialize_with = "serialize_bitvec")]
    #[serde(deserialize_with = "deserialize_bitvec")]
    bit_array: BitVec<u8, Lsb0>,
    num_hash_functions: usize,
    bit_count: usize,
}

fn serialize_bitvec<S>(bv: &BitVec<u8, Lsb0>, s: S) -> Result<S::Ok, S::Error>
where
    S: serde::Serializer,
{
    let bytes: Vec<u8> = bv.as_raw_slice().to_vec();
    bytes.serialize(s)
}

fn deserialize_bitvec<'de, D>(d: D) -> Result<BitVec<u8, Lsb0>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    let bytes: Vec<u8> = Vec::deserialize(d)?;
    Ok(BitVec::from_vec(bytes))
}

impl BloomFilter {
    pub fn new(expected_items: usize, false_positive_rate: f64) -> Self {
        let bit_count = Self::optimal_bit_count(expected_items, false_positive_rate);
        let num_hash_functions = Self::optimal_hash_count(bit_count, expected_items);
        let bit_array = bitvec![u8, Lsb0; 0; bit_count];
        BloomFilter {
            bit_array,
            num_hash_functions,
            bit_count,
        }
    }

    fn optimal_bit_count(n: usize, p: f64) -> usize {
        let m = -((n as f64) * p.ln() / (2.0_f64.ln().powi(2)));
        m.ceil() as usize
    }

    fn optimal_hash_count(m: usize, n: usize) -> usize {
        let k = ((m as f64 / n as f64) * 2.0_f64.ln()).ceil() as usize;
        std::cmp::max(k, 1)
    }

    fn get_hashes<T: Hash>(&self, item: &T) -> Vec<usize> {
        let mut hasher1 = std::collections::hash_map::DefaultHasher::new();
        let mut hasher2 = std::collections::hash_map::DefaultHasher::new();
        item.hash(&mut hasher1);
        item.hash(&mut hasher2);
        let h1 = hasher1.finish();
        let h2 = hasher2.finish();
        (0..self.num_hash_functions)
            .map(|i| {
                let h = h1.wrapping_add((i as u64).wrapping_mul(h2));
                (h as usize) % self.bit_count
            })
            .collect()
    }

    pub fn insert<T: Hash>(&mut self, item: &T) {
        for pos in self.get_hashes(item) {
            self.bit_array.set(pos, true);
        }
    }

    pub fn contains<T: Hash>(&self, item: &T) -> bool {
        self.get_hashes(item).iter().all(|&pos| self.bit_array[pos])
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic_insert_contains() {
        let mut bf = BloomFilter::new(1000, 0.01);
        bf.insert(&"hello");
        bf.insert(&"world");
        assert!(bf.contains(&"hello"));
        assert!(bf.contains(&"world"));
        assert!(!bf.contains(&"missing"));
    }
}

