#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic_insert_contains() {
        let mut bf = BloomFilter::new(1000, 0.01);
        bf.insert(&"hello");
        bf.insert(&"world");
        assert!(bf.contains(&"hello"));
        assert!(bf.contains(&"world"));
        assert!(!bf.contains(&"missing"));
    }

    #[test]
    fn test_serde_roundtrip_json() {
        let mut bf = BloomFilter::new(1000, 0.01);
        bf.insert(&"hello");
        bf.insert(&"world");
        let json = serde_json::to_string(&bf).unwrap();
        let bf2: BloomFilter = serde_json::from_str(&json).unwrap();
        assert!(bf2.contains(&"hello"));
        assert!(bf2.contains(&"world"));
    }

    #[test]
    fn test_serde_roundtrip_bincode() {
        let mut bf = BloomFilter::new(1000, 0.01);
        bf.insert(&"hello");
        bf.insert(&"world");
        let bytes = bincode::serialize(&bf).unwrap();
        let bf2: BloomFilter = bincode::deserialize(&bytes).unwrap();
        assert!(bf2.contains(&"hello"));
        assert!(bf2.contains(&"world"));
    }
}

