use serde::{Deserialize, Serialize};
use std::collections::hash_map::DefaultHasher;
use std::hash::{Hash, Hasher};
use twox_hash::XxHash64;

/// A probabilistic data structure that tests for set membership.
/// False positives are possible, but false negatives are not.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BloomFilter {
    /// The bit array storing membership data
    bit_array: Vec<u8>,
    /// Number of hash functions used
    num_hashers: u32,
    /// Expected number of items to be inserted
    expected_items: usize,
    /// Desired false positive rate
    fp_rate: f64,
}

impl BloomFilter {
    /// Create a new BloomFilter with the given expected number of items
    /// and desired false positive rate.
    pub fn new(expected_items: usize, fp_rate: f64) -> Self {
        let bit_count = Self::optimal_bit_count(expected_items, fp_rate);
        let num_hashers = Self::optimal_hasher_count(bit_count, expected_items);
        let byte_count = (bit_count + 7) / 8;

        BloomFilter {
            bit_array: vec![0u8; byte_count],
            num_hashers,
            expected_items,
            fp_rate,
        }
    }

    /// Calculate the optimal number of bits using: m = -(n * ln(p)) / (ln2)^2
    fn optimal_bit_count(expected_items: usize, fp_rate: f64) -> usize {
        let m = -(expected_items as f64 * fp_rate.ln()) / (2.0_f64.ln().powi(2));
        m.ceil() as usize
    }

    /// Calculate the optimal number of hash functions using: k = (m/n) * ln2
    fn optimal_hasher_count(bit_count: usize, expected_items: usize) -> u32 {
        let k = ((bit_count as f64 / expected_items as f64) * 2.0_f64.ln()).ceil();
        k.max(1) as u32
    }

    /// Generate hash values for a given item using double hashing technique.
    fn get_hashes<T: Hash>(&self, item: &T) -> Vec<usize> {
        let mut hasher1 = DefaultHasher::new();
        item.hash(&mut hasher1);
        let hash1 = hasher1.finish();

        let mut hasher2 = XxHash64::default();
        item.hash(&mut hasher2);
        let hash2 = hasher2.finish();

        let bit_count = self.bit_array.len() * 8;
        (0..self.num_hashers)
            .map(|i| {
                // Double hashing: h(i) = (h1 + i * h2) % m
                ((hash1 as usize).wrapping_add(i as usize * hash2 as usize)) % bit_count
            })
            .collect()
    }

    /// Insert an item into the bloom filter.
    pub fn insert<T: Hash>(&mut self, item: &T) {
        for pos in self.get_hashes(item) {
            let byte_idx = pos / 8;
            let bit_idx = (pos % 8) as u8;
            self.bit_array[byte_idx] |= 1 << bit_idx;
        }
    }

    /// Check if an item might be in the set. Returns false only if the
    /// item is definitely not in the set.
    pub fn might_contain<T: Hash>(&self, item: &T) -> bool {
        for pos in self.get_hashes(item) {
            let byte_idx = pos / 8;
            let bit_idx = (pos % 8) as u8;
            if self.bit_array[byte_idx] & (1 << bit_idx) == 0 {
                return false;
            }
        }
        true
    }

    /// Returns the current false positive rate based on the number of items inserted.
    pub fn estimated_fp_rate(&self, inserted_count: usize) -> f64 {
        let bit_count = self.bit_array.len() * 8;
        let k = self.num_hashers as f64;
        let m = bit_count as f64;
        let n = inserted_count as f64;
        (1.0 - (-k * n / m).exp()).powf(k)
    }

    /// Serialize the bloom filter to bytes using bincode.
    pub fn to_bytes(&self) -> Result<Vec<u8>, Box<dyn std::error::Error>> {
        Ok(bincode::serialize(self)?)
    }

    /// Deserialize a bloom filter from bytes using bincode.
    pub fn from_bytes(bytes: &[u8]) -> Result<Self, Box<dyn std::error::Error>> {
        Ok(bincode::deserialize(bytes)?)
    }

    /// Returns the number of bytes used by the bit array.
    pub fn memory_usage(&self) -> usize {
        self.bit_array.len()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_insert_and_query() {
        let mut bf = BloomFilter::new(1000, 0.01);
        bf.insert(&"hello");
        bf.insert(&"world");
        bf.insert(&42);

        assert!(bf.might_contain(&"hello"));
        assert!(bf.might_contain(&"world"));
        assert!(bf.might_contain(&42));
        assert!(!bf.might_contain(&"not_inserted"));
    }

    #[test]
    fn test_serialization_bincode() {
        let mut bf = BloomFilter::new(1000, 0.01);
        bf.insert(&"hello");
        bf.insert(&"world");

        let bytes = bf.to_bytes().unwrap();
        let deserialized: BloomFilter = BloomFilter::from_bytes(&bytes).unwrap();

        assert!(deserialized.might_contain(&"hello"));
        assert!(deserialized.might_contain(&"world"));
        assert!(!deserialized.might_contain(&"not_inserted"));
    }

    #[test]
    fn test_serialization_json() {
        let mut bf = BloomFilter::new(1000, 0.01);
        bf.insert(&"hello");

        let json = serde_json::to_string(&bf).unwrap();
        let deserialized: BloomFilter = serde_json::from_str(&json).unwrap();

        assert!(deserialized.might_contain(&"hello"));
    }

