  11     pub id: u64,
  12     tx: mpsc::Sender<ReplicaMsg>,
  13 }
  14 
  15 impl ReplicaHandle {
  16     pub async fn call(&self, msg: ReplicaMsg) -> Result<ReplicaResponse, ActorError> {
  17         let (resp_tx, resp_rx) = oneshot::channel();
  18         // ... wrap msg with oneshot, send, await response
  19         self.tx.send(msg_with_oneshot).await?;
  20         Ok(resp_rx.await?)
  21     }
  22 }
  23 
  24 pub struct ReplicaActor {
  25     rx: mpsc::Receiver<ReplicaMsg>,
  26     coordinator: CoordinatorHandle,
  27 }
  28 
  29 impl ReplicaActor {
  30     pub async fn run(&mut self) {
  31         while let Some(msg) = self.rx.recv().await {
  32             match msg {
  33                 ReplicaMsg::SyncState { data, tx } => {
  34                     let result = self.handle_sync(data).await;
  35                     let _ = tx.send(result);
  36                 },
  37                 ReplicaMsg::Ack { correlation_id, tx } => {
  38                     // DEADLOCK: replica calls coordinator.call() while
  39                     // coordinator is calling replica.call() (GetState/Status)
  40                     let resp = self.coordinator
  41                         .call(CoordMsg::BroadcastResult { correlation_id }).await.unwrap();
  42                     let _ = tx.send(AckResult::from(resp));
  43                 },
  44                 ReplicaMsg::Status { tx } => {
  45                     let _ = tx.send(self.status.clone());
  46                 },
  47                 ReplicaMsg::GetState { tx } => {
  48                     let _ = tx.send(self.state.clone());
  49                 },
  50             }
  51         }
  52     }
  53 }

