type Server struct {
	pb.UnimplementedEventServiceServer
	eventCh chan *pb.Event
}

func (s *Server) Subscribe(req *pb.SubscribeRequest, stream pb.EventService_SubscribeServer) error {
	log.Printf("client subscribed: filter=%s", req.Filter)

	ch := make(chan *pb.Event, 64)

	// Register the channel to receive events
	s.registerSubscriber(ch)
	defer s.unregisterSubscriber(ch)

	// Forward events to the client in a goroutine
	go s.forwardEvents(stream, ch)

	// Block until context is done
	<-stream.Context().Done()
	log.Printf("client disconnected: %v", stream.Context().Err())
	return nil
}

func (s *Server) forwardEvents(stream pb.EventService_SubscribeServer, ch <-chan *pb.Event) {
	for ev := range ch {
		if err := stream.Send(ev); err != nil {
			log.Printf("send error: %v", err)
			return
		}
	}
}

func (s *Server) registerSubscriber(ch chan<- *pb.Event) {
	// adds ch to subscriber list
}

func (s *Server) unregisterSubscriber(ch chan<- *pb.Event) {
	// removes ch from subscriber list and closes it
}

// pkg/server/stream_handler.go (lines 72-95 reviewed again)

// The issue: forwardEvents goroutine has no way to know the stream context
// was cancelled. When the client disconnects:
//   1. <-stream.Context().Done() unblocks in Subscribe()
//   2. Subscribe() returns, calling unregisterSubscriber(ch) which closes ch
//   3. BUT: if forwardEvents is blocked on stream.Send(), it may hang
//      indefinitely because Send() on a cancelled stream doesn't always
//      return immediately — it can block on the internal transport.
//   4. Even when the channel is closed and range exits, there's a race
//      where the goroutine may try to Send on a closed stream.
//
// The fix: forwardEvents must select on ch AND context cancellation,
// and Subscribe must wait for forwardEvents to finish before returning.

