	go s.forwardEvents(stream, ch, done)

	select {
	case <-stream.Context().Done():
		log.Printf("client disconnected: %v", stream.Context().Err())
	case <-done:
		// forwardEvents exited due to send error or closed channel
	}

	// Wait for forwardEvents to fully exit before returning.
	// This guarantees the goroutine is cleaned up before the
	// stream is torn down by the gRPC framework.
	<-done

	return nil
}

func (s *Server) forwardEvents(stream pb.EventService_SubscribeServer, ch <-chan *pb.Event, done chan<- struct{}) {
	defer close(done)

	ctx := stream.Context()
	for {
		select {
		case <-ctx.Done():
			// Client disconnected or context cancelled — stop sending.
			log.Printf("forwardEvents: context done: %v", ctx.Err())
			return
		case ev, ok := <-ch:
			if !ok {
				// Channel was closed by unregisterSubscriber.
				log.Printf("forwardEvents: event channel closed")
				return
			}
			if err := stream.Send(ev); err != nil {
				log.Printf("forwardEvents: send error: %v", err)
				return
			}
		}
	}
}

func (s *Server) registerSubscriber(ch chan<- *pb.Event) {
	// adds ch to subscriber list
}

func (s *Server) unregisterSubscriber(ch chan<- *pb.Event) {
	// removes ch from subscriber list and closes it
}

